def gen(rng, size):
    n = max(1, size)
    chars = []
    cur = rng.randint(0, 25)
    for _ in range(n):
        r = rng.random()
        if r < 0.5 and cur < 25:
            cur += 1
        elif r < 0.7:
            cur = rng.randint(0, 25)
        chars.append(chr(ord('a') + cur))
    return [''.join(chars)]

