class Solution:
    def longestContinuousSubstring(self, s):
        n = len(s)
        best = 0
        for i in range(n):
            j = i
            while j + 1 < n and ord(s[j + 1]) - ord(s[j]) == 1:
                j += 1
            best = max(best, j - i + 1)
        return best

