var longestContinuousSubstring = function(s) {
    let best = 1, run = 1;
    for (let i = 1; i < s.length; i++) {
        if (s.charCodeAt(i) - s.charCodeAt(i - 1) === 1) run++;
        else run = 1;
        if (run > best) best = run;
    }
    return best;
};
